import{_ as t,c as e,a1 as a,o as r}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Công cụ Giao diện Đồ họa (GUI) cho Enumeration trên Windows","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md","filePath":"vi/categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md"}'),o={name:"vi/categories/ethical-hacking-labs/3-enumeration/4-Windows-EnumerationTools.md"};function c(h,n,i,s,l,d){return r(),e("div",null,n[0]||(n[0]=[a('<h1 id="cong-cu-giao-dien-đo-hoa-gui-cho-enumeration-tren-windows" tabindex="-1">Công cụ Giao diện Đồ họa (GUI) cho Enumeration trên Windows <a class="header-anchor" href="#cong-cu-giao-dien-đo-hoa-gui-cho-enumeration-tren-windows" aria-label="Permalink to &quot;Công cụ Giao diện Đồ họa (GUI) cho Enumeration trên Windows&quot;">​</a></h1><h2 id="global-network-inventory" tabindex="-1">Global Network Inventory <a class="header-anchor" href="#global-network-inventory" aria-label="Permalink to &quot;Global Network Inventory&quot;">​</a></h2><p>Global Network Inventory được sử dụng như một công cụ quét kiểm toán trong môi trường không cần triển khai và không cần agent. Nó quét máy tính theo phạm vi IP, theo miền và máy đơn hoặc nhiều máy, như được định nghĩa bởi file host của Global Network Inventory. Bạn có thể enumerate NetBIOS, Nhóm người dùng, Người dùng, Phần mềm đang chạy, BIOS và nhiều hơn nữa. [Dùng thử/Trả phí] <a href="http://www.magnetosoft.com/product/global_network_inventory/download" target="_blank" rel="noreferrer">http://www.magnetosoft.com/product/global_network_inventory/download</a></p><h2 id="advanced-ip-scanner" tabindex="-1">Advanced IP Scanner <a class="header-anchor" href="#advanced-ip-scanner" aria-label="Permalink to &quot;Advanced IP Scanner&quot;">​</a></h2><p>Công cụ quét mạng miễn phí để phân tích LAN. Chương trình hiển thị tất cả các thiết bị mạng, cho phép bạn truy cập các thư mục được chia sẻ, cung cấp điều khiển máy tính từ xa (qua RDP và Radmin), và thậm chí có thể tắt máy tính từ xa. Dễ sử dụng và chạy ở dạng portable. Đây nên là lựa chọn đầu tiên cho mọi quản trị mạng. [Miễn phí] <a href="https://www.advanced-ip-scanner.com/" target="_blank" rel="noreferrer">https://www.advanced-ip-scanner.com/</a></p><h2 id="hyena" tabindex="-1">Hyena <a class="header-anchor" href="#hyena" aria-label="Permalink to &quot;Hyena&quot;">​</a></h2><p>Hyena cung cấp báo cáo Active Directory (AD) mở rộng, với các công cụ tích hợp cho truy vấn có thể tùy chỉnh, lọc, quản lý thuộc tính đối tượng, quản lý thuộc tính nâng cao và nhiều tính năng quản trị AD khác. [Dùng thử/Trả phí] <a href="https://systemtools.com/" target="_blank" rel="noreferrer">https://systemtools.com/</a></p><h2 id="superscan" tabindex="-1">SuperScan <a class="header-anchor" href="#superscan" aria-label="Permalink to &quot;SuperScan&quot;">​</a></h2><p>Công cụ quét cổng miễn phí cho Windows. Bạn có thể sử dụng chương trình để quét IP, HTTPS, FTP và nhiều hơn nữa. [Miễn phí] <a href="https://superscan.en.softonic.com/" target="_blank" rel="noreferrer">https://superscan.en.softonic.com/</a></p><h2 id="softperfect-networkscanner" tabindex="-1">SoftPerfect NetworkScanner <a class="header-anchor" href="#softperfect-networkscanner" aria-label="Permalink to &quot;SoftPerfect NetworkScanner&quot;">​</a></h2><p>Công cụ quét mạng có thể ping máy tính, quét cổng, phát hiện thư mục được chia sẻ và nhiều hơn nữa. [Dùng thử/Trả phí] <a href="https://www.softperfect.com/products/networkscanner/" target="_blank" rel="noreferrer">https://www.softperfect.com/products/networkscanner/</a></p><h2 id="adexplorer" tabindex="-1">ADExplorer <a class="header-anchor" href="#adexplorer" aria-label="Permalink to &quot;ADExplorer&quot;">​</a></h2><p>Active Directory Explorer (AD Explorer) là một trình xem và chỉnh sửa Active Directory (AD) nâng cao. Bạn có thể sử dụng AD Explorer để dễ dàng điều hướng cơ sở dữ liệu AD, xác định vị trí yêu thích, xem thuộc tính và thuộc tính của đối tượng mà không cần mở hộp thoại, chỉnh sửa quyền, xem schema của đối tượng và thực hiện các tìm kiếm phức tạp mà bạn có thể lưu và thực thi lại.</p><p><a href="https://docs.microsoft.com/en-us/sysinternals/downloads/adexplorer" target="_blank" rel="noreferrer">https://docs.microsoft.com/en-us/sysinternals/downloads/adexplorer</a></p>',14)]))}const u=t(o,[["render",c]]);export{m as __pageData,u as default};
